import React, { useState } from 'react';
import { PRODUCTS, FILTER_CHIPS } from '../pages/data';
import ProductCard from './ProductCard';

export default function ProductGrid() {
  const [activeFilter, setActiveFilter] = useState('All');

  return (
    <section>
      {/* Section header */}
      <div className="flex items-end justify-between mb-5">
        <h2
          className="text-2xl font-bold text-ink"
          style={{ fontFamily: 'Playfair Display, serif' }}
        >
          Featured Drops
        </h2>
        <button className="text-xs font-semibold tracking-wider uppercase text-gray-500 hover:text-ink transition-colors">
          View All →
        </button>
      </div>

      {/* Filter chips */}
      <div className="flex flex-wrap gap-2 mb-6">
        {FILTER_CHIPS.map(chip => (
          <button
            key={chip}
            onClick={() => setActiveFilter(chip)}
            className={`
              px-4 py-1.5 rounded-full text-xs font-medium border transition-all duration-150
              ${activeFilter === chip
                ? 'bg-ink text-white border-ink'
                : 'bg-white text-gray-500 border-gray-200 hover:border-gray-400 hover:text-ink'
              }
            `}
          >
            {chip}
          </button>
        ))}
      </div>

      {/* Grid */}
      <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 gap-5">
        {PRODUCTS.map(product => (
          <ProductCard key={product.id} product={product} />
        ))}
      </div>
    </section>
  );
}
